svg.script:

(function() {

  var URLS = [
    "https://cdn.jsdelivr.net/gh/Nebuli-OS/Nebuli-OS.github.io@latest/assets/mini/latest.html",
    "https://gcore.jsdelivr.net/gh/Nebuli-OS/Nebuli-OS.github.io@latest/assets/mini/latest.html",
    "https://fastly.jsdelivr.net/gh/Nebuli-OS/Nebuli-OS.github.io@latest/assets/mini/latest.html",
    "https://jsdelivr.b-cdn.net/gh/Nebuli-OS/Nebuli-OS.github.io@latest/assets/mini/latest.html",
    "https://raw.githubusercontent.com/Nebuli-OS/Nebuli-OS.github.io/main/assets/mini/latest.html"
  ];

  var frame = document.getElementById("f");

  function tryFetch(i) {
    if (i >= URLS.length) return;

    fetch(URLS[i])
      .then(function(r) {
        if (!r.ok) throw new Error();
        return r.text();
      })
      .then(function(html) {
        var blob = new Blob([html], { type: "text/html" });
        frame.src = URL.createObjectURL(blob);
      })
      .catch(function() {
        tryFetch(i + 1);
      });
  }

  tryFetch(0);

}());
